async (params, browser) => {
  // Search LinkedIn jobs
  await browser.open('https://www.linkedin.com/jobs/search/')

  // Wait for job results
  await browser.waitForSelector('.job-card-container, .jobs-search-results-list, .scaffold-layout__list', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract job listings
  const search_results = await browser.evaluate(`const jobs = []; const cards = document.querySelectorAll('.job-card-container, .job-card-list__entity-lockup, li.jobs-search-results__list-item'); for (let i = 0; i < Math.min(cards.length, 10); i++) { const card = cards[i]; const titleEl = card.querySelector('.job-card-list__title, .job-card-container__link strong, a.job-card-list__title--link strong'); const companyEl = card.querySelector('.job-card-container__primary-description, .artdeco-entity-lockup__subtitle span'); const locationEl = card.querySelector('.job-card-container__metadata-item, .artdeco-entity-lockup__caption span'); const linkEl = card.querySelector('a[href*="/jobs/view/"], a.job-card-list__title--link, a.job-card-container__link'); jobs.push({ title: titleEl ? titleEl.textContent.trim() : 'Unknown', company: companyEl ? companyEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', url: linkEl ? 'https://www.linkedin.com' + linkEl.getAttribute('href').split('?')[0] : '' }); } return { job_count: jobs.length, jobs: jobs }`)

  return search_results
}
